import React from 'react';
import { NavLink } from 'react-router-dom';
import { LayoutDashboard, Search, MessageSquare, Bell, User, Settings, LogOut } from 'lucide-react';

export default function Sidebar() {
  const navItems = [
    { to: "/dashboard", icon: <LayoutDashboard size={20} />, label: "Dashboard" },
    { to: "/explore", icon: <Search size={20} />, label: "Explore" },
    { to: "/messages", icon: <MessageSquare size={20} />, label: "Messages" },
    { to: "/notifications", icon: <Bell size={20} />, label: "Notifications" },
    { to: "/profile", icon: <User size={20} />, label: "Profile" },
    { to: "/settings", icon: <Settings size={20} />, label: "Settings" },
  ];

  return (
    <aside className="w-64 bg-white border-r border-slate-100 h-screen sticky top-0 flex flex-col p-6">
      <div className="text-teal-600 font-black text-2xl mb-10 tracking-tighter">WERTECH</div>
      <nav className="flex-1 space-y-2">
        {navItems.map((item) => (
          <NavLink 
            key={item.to} 
            to={item.to}
            className={({ isActive }) => `flex items-center gap-4 px-4 py-3 rounded-xl font-bold transition-all ${isActive ? 'bg-teal-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}
          >
            {item.icon} {item.label}
          </NavLink>
        ))}
      </nav>
      <button className="flex items-center gap-4 px-4 py-3 text-red-500 font-bold hover:bg-red-50 rounded-xl transition-all mt-auto">
        <LogOut size={20} /> Logout
      </button>
    </aside>
  );
}
